mapper.select:
SELECT d.id AS id, d.sharer_phone AS sharerPhone, d.sharer_name AS sharerName, d.sharer_social_credit_code AS sharerSocialCreditCode, d.registrant_phone AS registrantPhone, d.registrant_name AS registrantName, d.registrant_social_credit_code AS registrantSocialCreditCode, d.creator AS creator, d.add_datetime AS addDatetime, d.operator AS operator, d.operation_datetime AS operationDatetime, a.end_date AS endDate, a.storage_capacity AS storageCapacity, a.authorize_status AS authorizeStatus, a.payment_date AS paymentDate, a.area_id As areaId FROM eco_chain_distributor d LEFT JOIN eco_chain_enterprise_authorize a ON d.sharer_social_credit_code = a.credit_code WHERE 1 = 1
AND d.sharer_phone = #{params.sharerPhone}
AND d.sharer_name LIKE CONCAT('%', #{params.sharerName}, '%')
AND d.sharer_social_credit_code = #{params.sharerSocialCreditCode}
AND d.registrant_phone = #{params.registrantPhone}
AND d.registrant_name LIKE CONCAT('%', #{params.registrantName}, '%')
AND ( (#{params.isAuthorizeExpire} = 0 AND a.end_date <= NOW()) OR (#{params.isAuthorizeExpire} = 1 AND a.end_date > NOW()) )
AND a.payment_date >= #{params.startTime}
AND a.payment_date <= #{params.endTime}
ORDER BY d.operation_datetime
ASC DESC
